#include <stdio.h>

int main(){

	int n,ba,a,b,ro=1;
	scanf("%d %d %d",&n,&a,&b);
	ba=2;
	a--;
	b--;
	while(ba<=n){
		if(a/ba==b/ba)break;
		else{
			ba*=2;
			ro++;
		}
	}
	if(ba==n)printf("Final!\n");
	else printf("%d\n",ro);

	return 0;
}

