fn main() {
    let mut input = String::new();
    use std::io;
    use std::io::prelude::*;
    io::stdin().read_to_string(&mut input).unwrap();

    let mut it = input.split_whitespace();

    let n: u32 = it.next().unwrap().parse().unwrap();
    let a: u32 = it.next().unwrap().parse().unwrap();
    let b: u32 = it.next().unwrap().parse().unwrap();

    let oa = a - 1;
    let ob = b - 1;

    let logn = 31 - n.leading_zeros();

    let mut flag = n >> 1;
    let mut i = 0;

    let xor = oa ^ ob;

    while flag & xor == 0 {
        i += 1;
        flag >>= 1;
    }

    if flag == n >> 1 {
        println!("Final!");
    } else {
        println!("{}", logn - i)
    }
}
